<template>
    <VaForm ref="passwordForm" @submit.prevent="submit">
        <h1 class="font-semibold text-4xl mb-4">Forgot your password?</h1>
        <p class="text-base mb-4 leading-5">
            If you've forgotten your password, don't worry. Simply enter your email address below, and we'll send you an
            email with a temporary password. Restoring access to your account has never been easier.
        </p>
        <VaInput
            v-model="email"
            :rules="[(v) => !!v || 'Email field is required']"
            class="mb-4"
            label="Enter your email"
            type="email"
        />
        <VaButton class="w-full mb-2" @click="submit">Send password</VaButton>
        <VaButton :to="{ name: 'login' }" class="w-full" preset="secondary">Go back</VaButton>
    </VaForm>
</template>

<script lang="ts" setup>
import { ref } from 'vue'
import { useForm, useToast } from 'vuestic-ui'
import { useRouter } from 'vue-router'
import useFirebase from '../../composables/useFirebase'

const email = ref('')
const form = useForm('passwordForm')
const router = useRouter()
const { init } = useToast()
const { firebaseSendPasswordResetEmail } = useFirebase()

const submit = async () => {
    if (form.validate()) {
        try {
            await firebaseSendPasswordResetEmail(email.value)
            init({ message: 'Password reset email sent.', color: 'success' })
            router.push({ name: 'recover-password-email' })
        } catch (error) {
            console.error('Failed to send password reset email:', error)
            init({ message: 'Failed to send reset email. Please check your email and try again.', color: 'danger' })
        }
    }
}
</script>
